#include <bits/stdc++.h>
using namespace std;

const int N=510;

int n,m,a[N][N],s[N][N],u,v,f[N];

bool check2(int l,int r,int lim){
    int cnt=0;
    for(int i=1,lst=0;i<=m;i++)
        if(s[r][i]-s[r][lst]-s[l][i]+s[l][lst]>=lim)
            lst=i,cnt++;
    return cnt>=v;
}

bool check(int lim){
    memset(f,0,sizeof(f));
    for(int i=1,j=-1;i<=n;i++){
        while(check2(j+1,i,lim)) j++;
        if(j>=0)
            f[i]=f[j]+1;
    }
    return f[n]>=u;
}

int main(){
    scanf("%d%d%d%d",&n,&m,&u,&v);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+a[i][j];
        }
    int l=0,r=1e9;
    while(l<r){
        int mid=l+r+1>>1;
        if(check(mid)) l=mid;
        else r=mid-1;
    }
    printf("%d",l);
    return 0;
}
